```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Chain operations using operator| for fluent interface
  auto result = conn 
    | sqlgen::begin_transaction
    | (sqlgen::read<std::vector<Account>> | sqlgen::where("account_id"_c == from_account_id))
    | [&amount](const auto& conn, const std::vector<Account>& accounts) -> rfl::Result<sqlgen::Ref<sqlgen::sqlite::Connection>> {
        if (accounts.empty() || accounts[0].balance < amount) {
          return conn | sqlgen::rollback;
        }
        return conn;
      })
    | (sqlgen::update<Account>("balance"_c.set("balance"_c - amount)) | sqlgen::where("account_id"_c == from_account_id))
    | (sqlgen::update<Account>("balance"_c.set("balance"_c + amount)) | sqlgen::where("account_id"_c == to_account_id))
    | sqlgen::commit;

  return result.transform([](auto&&) { return true; }).or_else([](auto&& error) {
    // Log error or handle rollback automatically
    return false;
  });
}

}  // namespace transaction_transfer_funds
```

