  auto has_connection = [&](const std::string& u1, const std::string& u2) {
    for (const auto& conn : connections) {
      if ((conn.user1_name == u1 && conn.user2_name == u2) ||
          (conn.user1_name == u2 && conn.user2_name == u1)) {
        return true;
      }
    }
    return false;
  };

