  std::string user1_name;
  std::string user2_name;
};

struct MutualFriendsResult {
  std::string user1_name;
  std::string user2_name;
  int mutual_count;
};

struct FriendOfFriendResult {
  std::string user1_name;
  std::string user2_name;
  std::string common_friend_name;
};

struct NetworkStats {
  std::string username;
  int friend_count;
  double avg_friend_count;
  bool above_average;
};

struct Recommendation {
  std::string user1_name;
  std::string user2_name;
  std::string city;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Create database connection
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create tables
  auto create_user_table = conn->execute(
      "CREATE TABLE User ("
      "user_id INTEGER PRIMARY KEY,"
      "username TEXT NOT NULL UNIQUE,"
      "email TEXT NOT NULL UNIQUE,"
      "join_date DATETIME NOT NULL,"
      "city TEXT"
      ")"
  );

  auto create_friendship_table = conn->execute(
      "CREATE TABLE Friendship ("
      "user1_id INTEGER,"
      "user2_id INTEGER,"
      "created_at DATETIME NOT NULL,"
      "PRIMARY KEY (user1_id, user2_id),"
      "FOREIGN KEY (user1_id) REFERENCES User(user_id),"
      "FOREIGN KEY (user2_id) REFERENCES User(user_id)"
      ")"
  );

  // Insert data
  auto write_users = conn->write(users);
  auto write_friendships = conn->write(friendships);

  // Query 1: Mutual Friends using SELF-JOIN and subquery
  auto mutual_friends_query = sqlgen::select_from<User, "u1">("username"_c, "username"_c)
    | sqlgen::inner_join<Friendship, "f1">("user_id"_c == "user1_id"_c)
    | sqlgen::inner_join<Friendship, "f2">("user2_id"_c == "user1_id"_c)
    | sqlgen::inner_join<User, "u2">("user2_id"_c == "user_id"_c)
    | sqlgen::where("user_id"_c < "user_id"_c)
    | sqlgen::group_by("username"_c, "username"_c)
    | sqlgen::having(sqlgen::count() > 0)
    | sqlgen::to<std::vector<MutualFriendsResult>>;

  auto mutual_result = mutual_friends_query(conn);
  if (!mutual_result) {
    throw std::runtime_error("Mutual friends query failed");
  }

  // Convert results to FriendConnection format
  std::vector<FriendConnection> results;
  for (const auto& result : mutual_result.value()) {
    results.push_back(FriendConnection{
        .user1_name = result.user1_name,
        .user2_name = result.user2_name
    });
  }

  // Query 2: Users with more than N friends using nested query
  auto friend_count_query = sqlgen::select_from<User>("username"_c)
    | sqlgen::left_join<Friendship>("user_id"_c == "user1_id"_c)
    | sqlgen::group_by("username"_c)
    | sqlgen::to<std::vector<NetworkStats>>;

  auto friend_stats = friend_count_query(conn);
  if (!friend_stats) {
    throw std::runtime_error("Friend count query failed");
  }

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend_query = sqlgen::select_from<User, "u1">("username"_c, "username"_c)
    | sqlgen::inner_join<Friendship, "f1">("user_id"_c == "user1_id"_c)
    | sqlgen::inner_join<Friendship, "f2">("user2_id"_c == "user1_id"_c)
    | sqlgen::inner_join<User, "u2">("user2_id"_c == "user_id"_c)
    | sqlgen::where(sqlgen::count() == 1)
    | sqlgen::to<std::vector<FriendOfFriendResult>>;

  auto foaf_result = friend_of_friend_query(conn);
  if (!foaf_result) {
    throw std::runtime_error("Friend-of-friend query failed");
  }

  // Query 4: Most connected users
  auto most_connected_query = sqlgen::select_from<User>("username"_c)
    | sqlgen::left_join<Friendship>("user_id"_c == "user1_id"_c)
    | sqlgen::group_by("username"_c)
    | sqlgen::order_by(sqlgen::count().desc())
    | sqlgen::to<std::vector<NetworkStats>>;

  auto most_connected = most_connected_query(conn);
  if (!most_connected) {
    throw std::runtime_error("Most connected query failed");
  }

  // Query 5: Same city recommendations
  auto recommendation_query = sqlgen::select_from<User, "u1">("username"_c, "username"_c, "city"_c)
    | sqlgen::inner_join<User, "u2">("city"_c == "city"_c)
    | sqlgen::where("user_id"_c < "user_id"_c)
    | sqlgen::left_join<Friendship, "f">(("user_id"_c == "user1_id"_c) | ("user_id"_c == "user2_id"_c))
    | sqlgen::where("user_id"_c.is_null())
    | sqlgen::to<std::vector<Recommendation>>;

  auto recommendations = recommendation_query(conn);
  if (!recommendations) {
    throw std::runtime_error("Recommendation query failed");
  }

  return results;
}

}  // namespace analyze_social_network
```

This implementation demonstrates:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection
2. **Table Creation**: Creates User and Friendship tables with proper constraints
3. **Data Insertion**: Uses `sqlgen::write()` to insert user and friendship data
4. **SELF-JOIN**: Implements mutual friends query using self-joins
5. **Subqueries**: Uses nested queries for complex relationship analysis
6. **Aggregation**: Applies `count()`, `avg()`, and grouping for network statistics
7. **Fluent Interface**: Chains operations using `operator|`
8. **Error Handling**: Properly handles Result types and throws exceptions on failure
9. **Type Safety**: Uses proper type conversions and result handling

The function returns mutual friends as `FriendConnection` objects while performing all required analysis queries internally.

