  if (!create_parent_result) {
    return false; // Parent table creation failed
  }

  auto create_child_result = (sqlgen::create_table<Child>)(conn);
  if (!create_child_result) {
    return false; // Child table creation failed
  }

  // 3. Insert parent and child records with the same parent_id
  Parent parent{1, "Parent Record"};
  Child child{1, 1, "Child Record"};

  auto insert_result = sqlgen::insert(conn, parent, child);
  if (!insert_result) {
