bool update_set_operations() {
  using namespace sqlgen::literals;

  // 1. Establish database connection
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Create Account table by writing an empty vector
  std::vector<Account> empty_vec;
  auto write_result = sqlgen::write(conn, empty_vec);
  if (!write_result) {
    return false;
