  update_data.account_id = 1;
  update_data.balance = 1000.0;
  update_data.status = "active";

  std::vector<Account> update_vec{update_data};

  // Perform the update
  write_result = sqlgen::write(conn, update_vec);
  if (!write_result) {
    return false;
