/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Create SQLite database connection
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // 2. Create tables with if_not_exists option
  (sqlgen::create_table<Department> | sqlgen::if_not_exists)(conn).value();
  (sqlgen::create_table<Employee> | sqlgen::if_not_exists)(conn).value();

  // 3. Insert data into tables
  sqlgen::insert(conn, depts).value();
  sqlgen::insert(conn, emps).value();

  // 4. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_c, 
      "first_name"_c, 
      "last_name"_c, 
      "salary"_c
    )
    | sqlgen::inner_join<Employee, "e">("department_id"_c == "department_id"_c);

  auto inner_results = inner_query(conn).value();
  for (const auto& [dept_name, first_name, last_name, salary] : inner_results) {
    JoinAnalysis::JoinResult result{
        .department_name = dept_name,
        .first_name = first_name,
        .last_name = last_name,
        .salary = salary
    };
    result.department_name = dept_name;
    result.first_name = first_name;
    result.last_name = last_name;
    result.salary = salary;
    analysis.inner_join_results.push_back(std::move(result));
  }

  // 5. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(
      "first_name"_c, 
      "last_name"_c, 
      "salary"_c
    )
    | sqlgen::left_join<Department, "d">("department_id"_c == "department_id"_c);

  auto left_results = left_query(conn).value();
  for (const auto& [first_name, last_name, salary] : left_results) {
    JoinAnalysis::JoinResult result{
        .first_name = first_name,
        .last_name = last_name,
        .salary = salary
    };
    analysis.left_join_results.push_back(std::move(result));
  }

  // 6. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Department, "d">(
      "department_name"_c
    )
    | sqlgen::right_join<Employee, "e">("department_id"_c == "department_id"_c);

  auto right_results = right_query(conn).value();
  for (const auto& [dept_name] : right_results) {
    JoinAnalysis::JoinResult result{
        .department_name = dept_name
    };
    analysis.right_join_results.push_back(std::move(result));
  }

  // 7. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">(
      "department_name"_c
    )
    | sqlgen::full_join<Employee, "e">("department_id"_c == "department_id"_c);

  auto full_results = full_query(conn).value();
  for (const auto& [dept_name] : full_results) {
    JoinAnalysis::JoinResult result{
        .department_name = dept_name
    };
    analysis.full_join_results.push_back(std::move(result));
  }

  return analysis;
}

}  // namespace analyze_department_employees
