  static constexpr const char* tablename = "OrderSummaryView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
  double total;
};

/**
 * Description: This function demonstrates creating a view.
 * Returns: std::vector<OrderSummary>.
 */
std::vector<OrderSummary> create_view_order_summary() {
    // 1. Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

    // 2. Drop the view if it exists using drop<OrderSummary> | if_exists
    (sqlgen::drop<OrderSummary> | sqlgen::if_exists)(conn).value();

    // 3. Create the view using create_as<OrderSummary> with a select_from statement
    auto select_stmt = sqlgen::select_from<Order, OrderItem>(
        Order::order_id, 
        Order::customer, 
        (OrderItem::unit_price * OrderItem::quantity).sum().as<"total">()
    ) | sqlgen::inner_join(Order::order_id == OrderItem::order_id)
      | sqlgen::group_by(Order::order_id, Order::customer);

    auto create_view = sqlgen::create_as<OrderSummary>(select_stmt);
    create_view(conn).value();

    // 4. Read from the view using read<std::vector<OrderSummary>>
    auto result = (sqlgen::read<std::vector<OrderSummary>>)(conn).value();

    // 5. Return the result
    return result;
